import { mkdir, readFile, writeFile } from "node:fs/promises";
import { dirname, resolve } from "node:path";

export const SHOPPING_PROFILE_SCHEMA_VERSION = 1;
export const DEFAULT_SHOPPING_PROFILE_PATH = "data/shopping-profile.json";

export function createDefaultShoppingProfile(overrides = {}) {
  return normalizeShoppingProfile({
    country: "LV",
    currency: "EUR",
    sizes: {},
    budgetAnchors: {},
    hardExclusions: [],
    perItemPriceCeiling: { amount: 0, currency: "EUR" },
    enabledRetailers: [],
    ...overrides,
  });
}

export async function readShoppingProfile(filePath = DEFAULT_SHOPPING_PROFILE_PATH) {
  try {
    const raw = await readFile(resolve(filePath), "utf8");
    return normalizeShoppingProfile(JSON.parse(raw));
  } catch (err) {
    if (err.code === "ENOENT") {
      return createDefaultShoppingProfile();
    }
    throw err;
  }
}

export async function writeShoppingProfile(profile, filePath = DEFAULT_SHOPPING_PROFILE_PATH) {
  const normalized = normalizeShoppingProfile(profile);
  const target = resolve(filePath);
  await mkdir(dirname(target), { recursive: true });
  await writeFile(target, `${JSON.stringify(normalized, null, 2)}\n`, "utf8");
  return normalized;
}

export async function updateShoppingProfile(patch, filePath = DEFAULT_SHOPPING_PROFILE_PATH) {
  const current = await readShoppingProfile(filePath);
  const next = normalizeShoppingProfile({
    ...current,
    ...patch,
    sizes: patch.sizes ? { ...current.sizes, ...patch.sizes } : current.sizes,
    budgetAnchors: patch.budgetAnchors
      ? { ...current.budgetAnchors, ...patch.budgetAnchors }
      : current.budgetAnchors,
  });
  return writeShoppingProfile(next, filePath);
}

export function normalizeShoppingProfile(profile) {
  if (!profile || typeof profile !== "object" || Array.isArray(profile)) {
    throw new TypeError("Shopping profile must be an object.");
  }

  const country = normalizeCode(profile.country, "country", 2);
  const currency = normalizeCode(profile.currency, "currency", 3);
  const perItemPriceCeiling = normalizeMoney(
    profile.perItemPriceCeiling,
    "perItemPriceCeiling",
    currency,
  );

  return {
    schemaVersion: SHOPPING_PROFILE_SCHEMA_VERSION,
    country,
    currency,
    sizes: normalizeRecord(profile.sizes, "sizes", normalizeSize),
    budgetAnchors: normalizeRecord(profile.budgetAnchors, "budgetAnchors", (value, key) =>
      normalizeBudgetAnchor(value, key, currency),
    ),
    hardExclusions: normalizeUniqueStringArray(profile.hardExclusions, "hardExclusions"),
    perItemPriceCeiling,
    enabledRetailers: normalizeUniqueStringArray(profile.enabledRetailers, "enabledRetailers"),
  };
}

function normalizeCode(value, field, length) {
  if (typeof value !== "string") {
    throw new TypeError(`${field} must be a string.`);
  }
  const normalized = value.trim().toUpperCase();
  if (!new RegExp(`^[A-Z]{${length}}$`).test(normalized)) {
    throw new TypeError(`${field} must be a ${length}-letter uppercase code.`);
  }
  return normalized;
}

function normalizeRecord(value, field, normalizeValue) {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    throw new TypeError(`${field} must be an object.`);
  }

  return Object.fromEntries(
    Object.entries(value).map(([key, item]) => {
      const normalizedKey = String(key).trim();
      if (!normalizedKey) {
        throw new TypeError(`${field} keys must be non-empty strings.`);
      }
      return [normalizedKey, normalizeValue(item, normalizedKey)];
    }),
  );
}

function normalizeSize(value, key) {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    throw new TypeError(`sizes.${key} must be an object.`);
  }
  if (typeof value.value !== "string" || !value.value.trim()) {
    throw new TypeError(`sizes.${key}.value must be a non-empty string.`);
  }

  const normalized = { value: value.value.trim() };
  if (value.system !== undefined) {
    if (typeof value.system !== "string" || !value.system.trim()) {
      throw new TypeError(`sizes.${key}.system must be a non-empty string.`);
    }
    normalized.system = value.system.trim();
  }
  if (value.notes !== undefined) {
    if (typeof value.notes !== "string") {
      throw new TypeError(`sizes.${key}.notes must be a string.`);
    }
    normalized.notes = value.notes.trim();
  }
  return normalized;
}

function normalizeMoney(value, field, defaultCurrency) {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    throw new TypeError(`${field} must be an object.`);
  }
  if (typeof value.amount !== "number" || !Number.isFinite(value.amount) || value.amount < 0) {
    throw new TypeError(`${field}.amount must be a non-negative finite number.`);
  }

  return {
    amount: value.amount,
    currency:
      value.currency === undefined
        ? defaultCurrency
        : normalizeCode(value.currency, `${field}.currency`, 3),
  };
}

function normalizeBudgetAnchor(value, key, defaultCurrency) {
  const field = `budgetAnchors.${key}`;
  const normalized = normalizeMoney(value, field, defaultCurrency);

  if (value.cadence !== undefined) {
    if (!["per_item", "monthly", "seasonal", "annual"].includes(value.cadence)) {
      throw new TypeError(`${field}.cadence must be per_item, monthly, seasonal, or annual.`);
    }
    normalized.cadence = value.cadence;
  }
  if (value.notes !== undefined) {
    if (typeof value.notes !== "string") {
      throw new TypeError(`${field}.notes must be a string.`);
    }
    normalized.notes = value.notes.trim();
  }

  return normalized;
}

function normalizeUniqueStringArray(value, field) {
  if (!Array.isArray(value)) {
    throw new TypeError(`${field} must be an array.`);
  }

  return [...new Set(value.map((item) => {
    if (typeof item !== "string" || !item.trim()) {
      throw new TypeError(`${field} entries must be non-empty strings.`);
    }
    return item.trim();
  }))];
}

import { mkdtemp, rm } from "node:fs/promises";
import { join } from "node:path";
import { tmpdir } from "node:os";
import test from "node:test";
import assert from "node:assert/strict";

import {
  createDefaultShoppingProfile,
  readShoppingProfile,
  updateShoppingProfile,
  writeShoppingProfile,
} from "../src/shopping-profile.mjs";

test("creates a complete profile shape with required hard constraints", () => {
  const profile = createDefaultShoppingProfile({
    country: "lv",
    currency: "eur",
    sizes: {
      tops: { value: "M", system: "International" },
      shoes: { value: "42", system: "EU" },
    },
    budgetAnchors: {
      jeans: { amount: 80, cadence: "seasonal", notes: "Wait for sale" },
    },
    hardExclusions: ["leather", "leather", "dry clean only"],
    perItemPriceCeiling: { amount: 150 },
    enabledRetailers: ["Zalando", "ASOS", "Zalando"],
  });

  assert.equal(profile.country, "LV");
  assert.equal(profile.currency, "EUR");
  assert.deepEqual(Object.keys(profile.sizes), ["tops", "shoes"]);
  assert.equal(profile.budgetAnchors.jeans.currency, "EUR");
  assert.equal(profile.budgetAnchors.jeans.cadence, "seasonal");
  assert.equal(profile.budgetAnchors.jeans.notes, "Wait for sale");
  assert.deepEqual(profile.hardExclusions, ["leather", "dry clean only"]);
  assert.equal(profile.perItemPriceCeiling.currency, "EUR");
  assert.deepEqual(profile.enabledRetailers, ["Zalando", "ASOS"]);
});

test("persists profile data so it can be read by a later process", async () => {
  const dir = await mkdtemp(join(tmpdir(), "shopping-profile-"));
  const path = join(dir, "profile.json");

  try {
    await writeShoppingProfile(
      createDefaultShoppingProfile({
        country: "DE",
        currency: "EUR",
        perItemPriceCeiling: { amount: 200 },
        enabledRetailers: ["About You"],
      }),
      path,
    );

    const reloaded = await readShoppingProfile(path);

    assert.equal(reloaded.country, "DE");
    assert.equal(reloaded.perItemPriceCeiling.amount, 200);
    assert.deepEqual(reloaded.enabledRetailers, ["About You"]);
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

test("updates fields programmatically while preserving existing records", async () => {
  const dir = await mkdtemp(join(tmpdir(), "shopping-profile-"));
  const path = join(dir, "profile.json");

  try {
    await writeShoppingProfile(
      createDefaultShoppingProfile({
        sizes: { tops: { value: "L" } },
        budgetAnchors: { coats: { amount: 180 } },
      }),
      path,
    );

    const updated = await updateShoppingProfile(
      {
        sizes: { shoes: { value: "43", system: "EU" } },
        budgetAnchors: { shirts: { amount: 60 } },
        hardExclusions: ["polyester"],
      },
      path,
    );

    assert.deepEqual(Object.keys(updated.sizes), ["tops", "shoes"]);
    assert.deepEqual(Object.keys(updated.budgetAnchors), ["coats", "shirts"]);
    assert.deepEqual(updated.hardExclusions, ["polyester"]);
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

test("rejects invalid hard-constraint values", () => {
  assert.throws(
    () => createDefaultShoppingProfile({ country: "Latvia" }),
    /country must be a 2-letter uppercase code/,
  );
  assert.throws(
    () => createDefaultShoppingProfile({ perItemPriceCeiling: { amount: -1 } }),
    /perItemPriceCeiling\.amount must be a non-negative finite number/,
  );
});

import { appendFile, mkdir, readFile } from "node:fs/promises";
import { dirname, resolve } from "node:path";

export const SHOPPING_AUDIT_LOG_SCHEMA_VERSION = 1;
export const DEFAULT_SHOPPING_AUDIT_LOG_PATH = "data/shopping-audit-log.jsonl";
export const SHOPPING_AUDIT_ACTION_TYPES = Object.freeze([
  "search",
  "page_read",
  "cart_add",
  "cart_peek",
]);
export const SHOPPING_AUDIT_STATUSES = Object.freeze(["started", "succeeded", "failed"]);

let auditWriteQueue = Promise.resolve();

export function createShoppingAuditEntry(entry, now = new Date()) {
  if (!entry || typeof entry !== "object" || Array.isArray(entry)) {
    throw new TypeError("Shopping audit entry must be an object.");
  }

  const normalized = {
    schemaVersion: SHOPPING_AUDIT_LOG_SCHEMA_VERSION,
    actionType: normalizeEnum(entry.actionType, "actionType", SHOPPING_AUDIT_ACTION_TYPES),
    retailer: normalizeString(entry.retailer, "retailer"),
    timestamp: normalizeTimestamp(entry.timestamp ?? now),
    status: normalizeEnum(entry.status, "status", SHOPPING_AUDIT_STATUSES),
  };

  if (entry.screenshotPath !== undefined) {
    normalized.screenshotPath = normalizeString(entry.screenshotPath, "screenshotPath");
  }

  return normalized;
}

export function appendShoppingAuditEntry(
  entry,
  filePath = DEFAULT_SHOPPING_AUDIT_LOG_PATH,
  options = {},
) {
  const normalized = createShoppingAuditEntry(entry, options.now);
  const target = resolve(filePath);

  auditWriteQueue = auditWriteQueue
    .catch(() => undefined)
    .then(async () => {
      await mkdir(dirname(target), { recursive: true });
      await appendFile(target, `${JSON.stringify(normalized)}\n`, "utf8");
    })
    .catch((err) => {
      if (typeof options.onError === "function") {
        options.onError(err);
      }
    });

  return normalized;
}

export async function flushShoppingAuditLog() {
  await auditWriteQueue;
}

export async function readShoppingAuditLog(filePath = DEFAULT_SHOPPING_AUDIT_LOG_PATH) {
  try {
    const raw = await readFile(resolve(filePath), "utf8");
    return raw
      .split("\n")
      .filter(Boolean)
      .map((line) => createShoppingAuditEntry(JSON.parse(line)));
  } catch (err) {
    if (err.code === "ENOENT") {
      return [];
    }
    throw err;
  }
}

function normalizeEnum(value, field, allowedValues) {
  if (!allowedValues.includes(value)) {
    throw new TypeError(`${field} must be one of: ${allowedValues.join(", ")}.`);
  }
  return value;
}

function normalizeString(value, field) {
  if (typeof value !== "string" || !value.trim()) {
    throw new TypeError(`${field} must be a non-empty string.`);
  }
  return value.trim();
}

function normalizeTimestamp(value) {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.getTime())) {
    throw new TypeError("timestamp must be a valid date or ISO timestamp.");
  }
  return date.toISOString();
}

import { mkdtemp, readFile, rm } from "node:fs/promises";
import { join } from "node:path";
import { tmpdir } from "node:os";
import test from "node:test";
import assert from "node:assert/strict";

import {
  appendShoppingAuditEntry,
  createShoppingAuditEntry,
  flushShoppingAuditLog,
  readShoppingAuditLog,
} from "../src/shopping-audit-log.mjs";

test("creates normalized audit entries with optional screenshot paths", () => {
  const entry = createShoppingAuditEntry({
    actionType: "page_read",
    retailer: "  Zalando  ",
    timestamp: "2026-05-09T13:00:00.000Z",
    status: "succeeded",
    screenshotPath: " screenshots/page.png ",
  });

  assert.deepEqual(entry, {
    schemaVersion: 1,
    actionType: "page_read",
    retailer: "Zalando",
    timestamp: "2026-05-09T13:00:00.000Z",
    status: "succeeded",
    screenshotPath: "screenshots/page.png",
  });
});

test("appends audit entries asynchronously and preserves them across reads", async () => {
  const dir = await mkdtemp(join(tmpdir(), "shopping-audit-log-"));
  const path = join(dir, "audit.jsonl");

  try {
    const first = appendShoppingAuditEntry(
      {
        actionType: "search",
        retailer: "About You",
        status: "started",
      },
      path,
      { now: new Date("2026-05-09T13:01:00.000Z") },
    );
    const second = appendShoppingAuditEntry(
      {
        actionType: "cart_add",
        retailer: "About You",
        status: "succeeded",
      },
      path,
      { now: new Date("2026-05-09T13:02:00.000Z") },
    );

    assert.equal(first.actionType, "search");
    assert.equal(second.actionType, "cart_add");

    await flushShoppingAuditLog();
    const reloaded = await readShoppingAuditLog(path);

    assert.deepEqual(
      reloaded.map((entry) => [entry.actionType, entry.retailer, entry.timestamp, entry.status]),
      [
        ["search", "About You", "2026-05-09T13:01:00.000Z", "started"],
        ["cart_add", "About You", "2026-05-09T13:02:00.000Z", "succeeded"],
      ],
    );
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

test("stores one JSON object per line for durable append-only persistence", async () => {
  const dir = await mkdtemp(join(tmpdir(), "shopping-audit-log-"));
  const path = join(dir, "audit.jsonl");

  try {
    appendShoppingAuditEntry(
      {
        actionType: "cart_peek",
        retailer: "ASOS",
        status: "failed",
        screenshotPath: "debug/asos-cart.png",
      },
      path,
      { now: new Date("2026-05-09T13:03:00.000Z") },
    );

    await flushShoppingAuditLog();
    const raw = await readFile(path, "utf8");
    const lines = raw.trim().split("\n");

    assert.equal(lines.length, 1);
    assert.equal(JSON.parse(lines[0]).screenshotPath, "debug/asos-cart.png");
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

test("returns an empty audit log when no persisted log exists yet", async () => {
  const dir = await mkdtemp(join(tmpdir(), "shopping-audit-log-"));
  const path = join(dir, "missing.jsonl");

  try {
    assert.deepEqual(await readShoppingAuditLog(path), []);
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

test("rejects invalid audit entry values", () => {
  assert.throws(
    () => createShoppingAuditEntry({ actionType: "login", retailer: "ASOS", status: "started" }),
    /actionType must be one of/,
  );
  assert.throws(
    () => createShoppingAuditEntry({ actionType: "search", retailer: "", status: "started" }),
    /retailer must be a non-empty string/,
  );
  assert.throws(
    () => createShoppingAuditEntry({ actionType: "search", retailer: "ASOS", status: "done" }),
    /status must be one of/,
  );
});

import { mkdir, rm, writeFile } from "node:fs/promises";
import { resolve } from "node:path";

export const BROWSER_PROFILE_SCHEMA_VERSION = 1;
export const DEFAULT_BROWSER_PROFILES_ROOT = "data/browser-profiles";
export const BROWSER_PROFILE_METADATA_FILE = "retailer-profile.json";

export function normalizeRetailerIdentifier(retailerIdentifier) {
  if (typeof retailerIdentifier !== "string" || !retailerIdentifier.trim()) {
    throw new TypeError("retailerIdentifier must be a non-empty string.");
  }
  return retailerIdentifier.trim();
}

export function getRetailerBrowserProfileDirectory(
  retailerIdentifier,
  profilesRoot = DEFAULT_BROWSER_PROFILES_ROOT,
) {
  const normalized = normalizeRetailerIdentifier(retailerIdentifier);
  return resolve(profilesRoot, encodeRetailerIdentifier(normalized));
}

export async function ensureRetailerBrowserProfile(
  retailerIdentifier,
  profilesRoot = DEFAULT_BROWSER_PROFILES_ROOT,
) {
  const normalized = normalizeRetailerIdentifier(retailerIdentifier);
  const profileDirectory = getRetailerBrowserProfileDirectory(normalized, profilesRoot);
  const profile = createRetailerBrowserProfileDescriptor(normalized, profileDirectory);

  await mkdir(profileDirectory, { recursive: true });
  await writeFile(
    resolve(profileDirectory, BROWSER_PROFILE_METADATA_FILE),
    `${JSON.stringify(
      {
        schemaVersion: BROWSER_PROFILE_SCHEMA_VERSION,
        retailerIdentifier: normalized,
      },
      null,
      2,
    )}\n`,
    "utf8",
  );

  return profile;
}

export async function ensureEnabledRetailerBrowserProfiles(
  retailerIdentifiers,
  profilesRoot = DEFAULT_BROWSER_PROFILES_ROOT,
) {
  if (!Array.isArray(retailerIdentifiers)) {
    throw new TypeError("retailerIdentifiers must be an array.");
  }

  const uniqueRetailers = [...new Set(retailerIdentifiers.map(normalizeRetailerIdentifier))];
  return Promise.all(
    uniqueRetailers.map((retailerIdentifier) =>
      ensureRetailerBrowserProfile(retailerIdentifier, profilesRoot),
    ),
  );
}

export async function disconnectRetailerBrowserProfile(
  retailerIdentifier,
  profilesRoot = DEFAULT_BROWSER_PROFILES_ROOT,
) {
  const normalized = normalizeRetailerIdentifier(retailerIdentifier);
  const profileDirectory = getRetailerBrowserProfileDirectory(normalized, profilesRoot);

  await rm(profileDirectory, { recursive: true, force: true });

  return createRetailerBrowserProfileDescriptor(normalized, profileDirectory);
}

function createRetailerBrowserProfileDescriptor(retailerIdentifier, profileDirectory) {
  return {
    retailerIdentifier,
    profileDirectory,
    userDataDir: profileDirectory,
  };
}

function encodeRetailerIdentifier(retailerIdentifier) {
  return `retailer-${Buffer.from(retailerIdentifier, "utf8").toString("hex")}`;
}

import { mkdtemp, readFile, rm, stat, writeFile } from "node:fs/promises";
import { join, relative, sep } from "node:path";
import { tmpdir } from "node:os";
import test from "node:test";
import assert from "node:assert/strict";

import {
  BROWSER_PROFILE_METADATA_FILE,
  disconnectRetailerBrowserProfile,
  ensureEnabledRetailerBrowserProfiles,
  ensureRetailerBrowserProfile,
  getRetailerBrowserProfileDirectory,
} from "../src/shopping-browser-profiles.mjs";

test("assigns each retailer identifier a unique profile directory", async () => {
  const dir = await mkProfileRoot();

  try {
    const zalando = getRetailerBrowserProfileDirectory("Zalando", dir);
    const aboutYou = getRetailerBrowserProfileDirectory("About You", dir);
    const suspicious = getRetailerBrowserProfileDirectory("../Zalando", dir);

    assert.notEqual(zalando, aboutYou);
    assert.notEqual(zalando, suspicious);
    assert.equal(isInside(dir, zalando), true);
    assert.equal(isInside(dir, suspicious), true);
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

test("creates persistent browser profile directories for enabled retailers", async () => {
  const dir = await mkProfileRoot();

  try {
    const profiles = await ensureEnabledRetailerBrowserProfiles(["Zalando", "ASOS", "Zalando"], dir);

    assert.equal(profiles.length, 2);
    assert.deepEqual(
      profiles.map((profile) => profile.retailerIdentifier),
      ["Zalando", "ASOS"],
    );

    for (const profile of profiles) {
      assert.equal(profile.userDataDir, profile.profileDirectory);
      const metadata = JSON.parse(
        await readFile(join(profile.profileDirectory, BROWSER_PROFILE_METADATA_FILE), "utf8"),
      );
      assert.equal(metadata.retailerIdentifier, profile.retailerIdentifier);
    }
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

test("keeps existing session data when the profile is ensured again after restart", async () => {
  const dir = await mkProfileRoot();

  try {
    const profile = await ensureRetailerBrowserProfile("About You", dir);
    await writeFile(join(profile.profileDirectory, "Cookies"), "session=retained\n", "utf8");

    const reloaded = await ensureRetailerBrowserProfile("About You", dir);
    const cookieData = await readFile(join(reloaded.profileDirectory, "Cookies"), "utf8");

    assert.equal(reloaded.profileDirectory, profile.profileDirectory);
    assert.equal(cookieData, "session=retained\n");
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

test("disconnect removes only the selected retailer profile", async () => {
  const dir = await mkProfileRoot();

  try {
    const zalando = await ensureRetailerBrowserProfile("Zalando", dir);
    const asos = await ensureRetailerBrowserProfile("ASOS", dir);
    await writeFile(join(zalando.profileDirectory, "Cookies"), "zalando-session\n", "utf8");
    await writeFile(join(asos.profileDirectory, "Cookies"), "asos-session\n", "utf8");

    const disconnected = await disconnectRetailerBrowserProfile("Zalando", dir);

    assert.equal(disconnected.profileDirectory, zalando.profileDirectory);
    await assert.rejects(stat(zalando.profileDirectory), { code: "ENOENT" });
    assert.equal(await readFile(join(asos.profileDirectory, "Cookies"), "utf8"), "asos-session\n");
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

test("rejects blank retailer identifiers", async () => {
  const dir = await mkProfileRoot();

  try {
    await assert.rejects(
      ensureRetailerBrowserProfile(" ", dir),
      /retailerIdentifier must be a non-empty string/,
    );
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

async function mkProfileRoot() {
  return mkdtemp(join(tmpdir(), "shopping-browser-profiles-"));
}

function isInside(root, target) {
  const path = relative(root, target);
  return path !== "" && !path.startsWith("..") && !path.includes(`..${sep}`);
}
